window.AIXIS = {
AXIS_KEYS: ['practicality', 'cost_performance', 'localization', 'safety', 'uniqueness'],
AXIS_LABELS: {
practicality: '実務適性',
cost_performance: '費用対効果',
localization: '日本語能力',
safety: '信頼性・安全性',
uniqueness: '革新性'
},
AXIS_SHORT: {
practicality: '実務適性',
cost_performance: '費用対効果',
localization: '日本語能力',
safety: '信頼性・安全性',
uniqueness: '革新性'
},
AXIS_MIX: {
practicality: { auto: 40, manual: 60 },
cost_performance: { auto: 30, manual: 70 },
localization: { auto: 70, manual: 30 },
safety: { auto: 35, manual: 65 },
uniqueness: { auto: 40, manual: 60 }
},
TOOL_COLORS: [
'#6366f1', '#ec4899', '#14b8a6', '#f59e0b',
'#8b5cf6', '#06b6d4', '#f43f5e', '#84cc16'
],
GRADES: [
{ min: 4.5, grade: 'S', label: 'S', color: '#C9A84C' },
{ min: 3.8, grade: 'A', label: 'A', color: '#8BA8C4' },
{ min: 3.0, grade: 'B', label: 'B', color: '#6B8A7A' },
{ min: 2.0, grade: 'C', label: 'C', color: '#8A7A6B' },
{ min: 0,   grade: 'D', label: 'D', color: '#8A5A5A' }
],
GRADE_NA: { grade: 'N/A', label: '評価不十分', color: '#a0aec0' },
MAX_SCORE: 5.0
};
function getGrade(score, gradeOverride) {
if (gradeOverride === 'N/A') return AIXIS.GRADE_NA;
for (const g of AIXIS.GRADES) {
if (score >= g.min) return g;
}
return AIXIS.GRADES[AIXIS.GRADES.length - 1];
}
function gradeClass(score) {
return 'grade-' + getGrade(score).grade;
}
function gradeColor(score) {
return getGrade(score).color;
}
function scoreLevel(score) {
if (score >= 4.0) return 'excellent';
if (score >= 3.0) return 'good';
if (score >= 2.0) return 'average';
return 'poor';
}
function scoreLevelColor(score) {
if (score >= 4.0) return '#8BA8C4';
if (score >= 3.0) return '#6B8A7A';
if (score >= 2.0) return '#8A7A6B';
return '#8A5A5A';
}
function formatScore(score) {
return score != null ? Number(score).toFixed(2) : '---';
}
function isDarkMode() {
return document.documentElement.classList.contains('dark');
}
function toggleTheme() {
const html = document.documentElement;
const isDark = html.classList.toggle('dark');
localStorage.setItem('aixis-theme', isDark ? 'dark' : 'light');
window.dispatchEvent(new CustomEvent('aixis-theme-change', { detail: { dark: isDark } }));
}
AIXIS.toggleTheme = toggleTheme;
AIXIS.isDarkMode = isDarkMode;
function getPlotlyLayout(overrides = {}) {
const dark = isDarkMode();
const textColor = dark ? '#e2e8f0' : '#2d3748';
const gridColor = dark ? '#2d3748' : '#e2e8f0';
const bgColor = 'rgba(0,0,0,0)';
const base = {
paper_bgcolor: bgColor,
plot_bgcolor: bgColor,
font: {
family: 'Inter, Noto Serif JP, serif',
color: textColor,
size: 13
},
margin: { t: 30, r: 30, b: 30, l: 30 },
showlegend: true,
legend: {
font: { color: textColor, size: 12 },
bgcolor: 'rgba(0,0,0,0)'
}
};
return { ...base, ...overrides };
}
function getRadarLayout(overrides = {}) {
const dark = isDarkMode();
const textColor = dark ? '#e2e8f0' : '#2d3748';
const gridColor = dark ? '#374151' : '#e2e8f0';
const base = getPlotlyLayout({
polar: {
radialaxis: {
visible: true,
range: [0, 5],
dtick: 1,
gridcolor: gridColor,
linecolor: gridColor,
tickfont: { color: textColor, size: 11 }
},
angularaxis: {
direction: 'clockwise',
gridcolor: gridColor,
linecolor: gridColor,
tickfont: { color: textColor, size: 12 }
},
bgcolor: 'rgba(0,0,0,0)'
}
});
return { ...base, ...overrides };
}
window.addEventListener('aixis-theme-change', () => {
document.querySelectorAll('.js-plotly-plot').forEach(el => {
if (el._renderChart) {
el._renderChart();
}
});
});
function _parseUTC(isoString) {
if (!isoString) return null;
return new Date(isoString.endsWith('Z') || isoString.includes('+') ? isoString : isoString + 'Z');
}
function formatDate(isoString) {
const d = _parseUTC(isoString);
if (!d || isNaN(d)) return '---';
return d.toLocaleDateString('ja-JP', { year: 'numeric', month: '2-digit', day: '2-digit', timeZone: 'Asia/Tokyo' });
}
function formatDateTime(isoString) {
const d = _parseUTC(isoString);
if (!d || isNaN(d)) return '---';
return d.toLocaleDateString('ja-JP', {
year: 'numeric', month: '2-digit', day: '2-digit',
hour: '2-digit', minute: '2-digit',
timeZone: 'Asia/Tokyo'
});
}
function getCSRFToken() {
const match = document.cookie.match(/(?:^|;\s*)aixis_csrf=([^;]+)/);
return match ? decodeURIComponent(match[1]) : '';
}
if (typeof htmx !== 'undefined') {
document.addEventListener('DOMContentLoaded', function() {
document.body.addEventListener('htmx:configRequest', function(evt) {
if (evt.detail && evt.detail.headers && evt.detail.verb !== 'get') {
evt.detail.headers['X-CSRF-Token'] = getCSRFToken();
}
});
});
}
async function aixisAPI(path, options = {}) {
const token = localStorage.getItem('aixis_token');
const method = (options.method || 'GET').toUpperCase();
const headers = { ...options.headers };
if (method !== 'GET' && method !== 'HEAD') {
if (!headers['Content-Type']) headers['Content-Type'] = 'application/json';
headers['X-CSRF-Token'] = getCSRFToken();
}
if (token) headers['Authorization'] = `Bearer ${token}`;
let response = await fetch(`/api/v1${path}`, { ...options, headers, credentials: 'same-origin' });
if (response.status === 401 && token) {
localStorage.removeItem('aixis_token');
const retryHeaders = { 'Content-Type': 'application/json', ...options.headers };
if (method !== 'GET' && method !== 'HEAD') {
retryHeaders['X-CSRF-Token'] = getCSRFToken();
}
response = await fetch(`/api/v1${path}`, { ...options, headers: retryHeaders, credentials: 'same-origin' });
}
if (response.status === 401) {
localStorage.removeItem('aixis_token');
if (!window.location.pathname.startsWith('/login')) {
window.location.href = '/login';
}
throw new Error('Unauthorized');
}
if (!response.ok) {
const error = await response.json().catch(() => ({ detail: 'Request failed' }));
throw new Error(error.detail || `HTTP ${response.status}`);
}
if (response.status === 204) return null;
return response.json();
}
function createGradeBadge(grade, size = '') {
const sizeClass = size === 'lg' ? 'grade-badge-lg' : '';
const safeGrade = String(grade || '').replace(/[^A-Za-z0-9\/]/g, '');
return `<span class="grade-badge grade-badge-stamp ${sizeClass} grade-${safeGrade}">${safeGrade}</span>`;
}
function createScoreBar(score, maxScore = 5.0) {
const pct = maxScore > 0 ? Math.min(100, (score / maxScore * 100)).toFixed(1) : '0';
const level = scoreLevel(score);
return `<div class="score-bar"><div class="score-bar-fill ${level}" style="width:${pct}%"></div></div>`;
}
function createStatusBadge(status) {
const labels = {
pending: '待機中',
running: '記録中',
scoring: 'スコアリング中',
aborting: '中止中...',
waiting_login: '記録中',
awaiting_manual: '手動評価待ち',
completed: '完了',
failed: '失敗',
cancelled: 'キャンセル',
aborted: '中止済み'
};
const safeStatus = String(status || '').replace(/[^a-z_]/g, '');
return `<span class="status-badge status-${safeStatus}">${labels[status] || safeStatus}</span>`;
}
function toggleMobileNav() {
const menu = document.getElementById('mobile-menu');
if (menu) {
menu.classList.toggle('hidden');
}
}
function initStatValues() {
var els = document.querySelectorAll('[data-countup]');
els.forEach(function(el) {
var target = parseFloat(el.dataset.countup);
if (!isNaN(target)) {
var isFloat = String(el.dataset.countup).indexOf('.') !== -1;
el.textContent = isFloat
? target.toFixed((String(el.dataset.countup).split('.')[1] || '').length)
: Math.floor(target).toLocaleString('ja-JP');
}
});
}
document.addEventListener('DOMContentLoaded', initStatValues);
AIXIS.setStatValue = function(el, value) { el.textContent = String(value); };